using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class UploadsController : ControllerBase
    {
        private readonly IWebHostEnvironment _hostingEnvironment;
        private readonly ILogger<UploadsController> _logger;

        public UploadsController(IWebHostEnvironment hostingEnvironment, ILogger<UploadsController> logger)
        {
            _hostingEnvironment = hostingEnvironment;
            _logger = logger;
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename cannot be empty.");
            }

            // Combine the web root path with the "uploads" folder and the filename
            // Ensure the "uploads" folder exists in your wwwroot or content root
            // For simplicity, this example assumes "uploads" is directly under the content root.
            // If you want it under wwwroot, use _hostingEnvironment.WebRootPath
            var uploadsFolderPath = Path.Combine(_hostingEnvironment.ContentRootPath, "uploads");
            var filePath = Path.Combine(uploadsFolderPath, filename);

            if (!System.IO.File.Exists(filePath))
            {
                _logger.LogWarning($"File not found: {filePath}");
                return NotFound();
            }

            try
            {
                var fileBytes = System.IO.File.ReadAllBytes(filePath);

                // Determine content type
                var provider = new FileExtensionContentTypeProvider();
                if (!provider.TryGetContentType(filename, out var contentType))
                {
                    contentType = "application/octet-stream"; // Default if type cannot be determined
                }

                return File(fileBytes, contentType, filename);
            }
            catch (UnauthorizedAccessException ex)
            {
                _logger.LogError(ex, $"Unauthorized access to file: {filePath}");
                return Forbid(); // Or StatusCode(403)
            }
            catch (IOException ex)
            {
                _logger.LogError(ex, $"Error reading file: {filePath}");
                return StatusCode(500, "Error reading the file.");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, $"An unexpected error occurred while serving file: {filePath}");
                return StatusCode(500, "An unexpected error occurred.");
            }
        }
    }
